<?php
namespace App\Services\Billing;use App\Models\{Plan,Subscription,Workspace};use App\Notifications\{SubscriptionReactivatedNotification,SubscriptionSuspendedNotification};use App\Services\Audit\AuditLogService;
class SubscriptionService{public function __construct(private AuditLogService $audit){}public function startTrial(Workspace $w,Plan $p):Subscription{return Subscription::create(['workspace_id'=>$w->id,'plan_id'=>$p->id,'status'=>'trial','trial_ends_at'=>now()->addDays(config('workproof.defaults.trial_days',14)),'current_period_start'=>today(),'current_period_end'=>now()->addDays(config('workproof.defaults.trial_days',14)),'billing_cycle'=>'monthly','gateway'=>'manual']);}public function changePlan(Workspace $w,Plan $p):Subscription{$s=$w->subscription()->latest()->first();$old=$s?->plan_id;if(!$s)$s=$this->startTrial($w,$p);else $s->update(['plan_id'=>$p->id]);$this->audit->log('subscription_plan_changed',$s,['plan_id'=>$old],['plan_id'=>$p->id],$w->id);return $s;}public function renewSubscription(Subscription $s):void{$s->update(['status'=>'active','current_period_start'=>today(),'current_period_end'=>today()->add($s->billing_cycle==='yearly'?'year':'month')]);$this->audit->log('subscription_renewed',$s,[],[],$s->workspace_id);}public function markPastDue(Subscription $s):void{$s->update(['status'=>'past_due']);$this->audit->log('subscription_past_due',$s,[],[],$s->workspace_id);}public function startGracePeriod(Subscription $s):void{$s->update(['status'=>'past_due','grace_ends_at'=>today()->addDays(config('billing.grace_days',7))]);}public function suspendExpiredSubscription(Subscription $s):void{$s->update(['status'=>'suspended']);$s->workspace?->update(['status'=>'suspended','suspended_at'=>now(),'suspension_reason'=>'Subscription grace period expired.']);$this->audit->log('subscription_suspended',$s,[],[],$s->workspace_id);$s->workspace?->owner?->notify(new SubscriptionSuspendedNotification($s));}public function reactivateSubscription(Subscription $s):void{$s->update(['status'=>'active','grace_ends_at'=>null]);$s->workspace?->update(['status'=>'active','suspended_at'=>null,'suspension_reason'=>null]);$this->audit->log('subscription_reactivated',$s,[],[],$s->workspace_id);$s->workspace?->owner?->notify(new SubscriptionReactivatedNotification($s));}}
